using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Breaking change 1 – Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
            // Preserve the old property name so existing 500K documents remain readable.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2 – Id format changed from "EntityType|Key" to just "Key" in EF Core 9.
            // Preserve the old "Product|{Id}" format so existing documents are still addressable.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id).ToJsonPropertyName("id");
            entity.UsePropertyAccessMode(PropertyAccessMode.Property);

            // Use the legacy id factory to keep generating "Product|<key>" ids
            // matching the 500K existing documents.
            entity.Property(p => p.Id)
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        base.OnConfiguring(optionsBuilder);
    }
}

// Breaking change 2 (continued) – Value generator that reproduces the EF Core 8 "EntityType|Key" id format.
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    public override string Next(EntityEntry entry)
        => $"{entry.Metadata.ShortName()}|{entry.Property("Id").CurrentValue}";
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

