arguments.new_str:
class CosmosQuery
{
    // Breaking change 3 – Synchronous I/O (ToList, Single, First, etc.) was removed
    // in EF Core 9 Cosmos provider and now throws InvalidOperationException.
    // All queries must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (safe because we
        // configured HasDiscriminator("Discriminator") to keep the old property name).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // ToList() → ToListAsync() (sync APIs removed in EF Core 9 Cosmos provider)
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

